changeSet.sql:
insert into au_rule(id, resource_type, resource_sub_type, handler, role_type, scope) select nextval('au_rule_seq'), 'REQUEST', code, 'requestAccessHandler', 'REGULATOR', null from request_type; insert into au_rule(id, resource_type, resource_sub_type, handler, role_type, scope) select nextval('au_rule_seq'), 'REQUEST', code, 'requestAccessHandler', 'OPERATOR', null from request_type where history_category = 'PERMIT' OR history_category = 'REPORTING' OR history_category = 'SYSTEM_MESSAGE_NOTIFICATION'; insert into au_rule(id, resource_type, resource_sub_type, handler, role_type, scope) select nextval('au_rule_seq'), 'REQUEST', code, 'requestAccountBasedAccessHandler', 'VERIFIER', null from request_type where history_category = 'PERMIT' OR history_category = 'REPORTING' OR history_category = 'SYSTEM_MESSAGE_NOTIFICATION';
INSERT INTO au_service_rule (rule_id, service_id) SELECT r.id, s.id FROM ( select id from au_rule where resource_type = 'REQUEST' and resource_sub_type is not null and role_type = 'REGULATOR' ) r CROSS JOIN ( select s.id from au_rule r join au_service_rule sr on sr.rule_id = r.id join au_service s on s.id = sr.service_id where r.resource_type = 'REQUEST' and r.resource_sub_type is null and r.role_type = 'REGULATOR' ) s;
INSERT INTO au_service_rule (rule_id, service_id) SELECT r.id, s.id FROM ( select id from au_rule where resource_type = 'REQUEST' and resource_sub_type is not null and role_type = 'OPERATOR' ) r CROSS JOIN ( select s.id from au_rule r join au_service_rule sr on sr.rule_id = r.id join au_service s on s.id = sr.service_id where r.resource_type = 'REQUEST' and r.resource_sub_type is null and r.role_type = 'OPERATOR' ) s;
INSERT INTO au_service_rule (rule_id, service_id) SELECT r.id, s.id FROM ( select id from au_rule where resource_type = 'REQUEST' and resource_sub_type is not null and role_type = 'VERIFIER' ) r CROSS JOIN ( select s.id from au_rule r join au_service_rule sr on sr.rule_id = r.id join au_service s on s.id = sr.service_id where r.resource_type = 'REQUEST' and r.resource_sub_type is null and r.role_type = 'VERIFIER' ) s;
--delete deprecated rules delete from au_service_rule where rule_id in ( select id from au_rule where resource_type = 'REQUEST' and resource_sub_type is null);
delete from au_rule where resource_type = 'REQUEST' and resource_sub_type is null;

